Ah, klasičan slučaj! 🐍 **Imam ja jednu prečicu za to...**

Trebaš **SOAP-to-REST adapter** — intermediate servis koji prevodi između dva sveta bez dotakanja legacy SOAP-a. Evo kako:

## Opcija 1: Python Flask Adapter (NAJPROSTIJA)

```python
from flask import Flask, request, jsonify
from zeep import Client  # SOAP biblioteka
import logging

app = Flask(__name__)
logging.basicConfig(level=logging.INFO)

# Konekcija na stari SOAP servis (NE MENJA SE!)
soap_client = Client(
    wsdl='http://legacy-soap-server:8080/services/CustomerService?wsdl',
    settings=zeep.Settings(strict=False)  # Tolerantniji parser
)

# REST endpoint koji delegira na SOAP
@app.route('/api/v2/customers/<customer_id>', methods=['GET'])
def get_customer(customer_id):
    try:
        # Pozovi stari SOAP metod
        soap_response = soap_client.service.GetCustomer(
            CustomerID=customer_id
        )

        # Transformuj SOAP u JSON (PREČICA!)
        return jsonify({
            'id': soap_response['CustomerID'],
            'name': soap_response['CustomerName'],
            'email': soap_response['EmailAddress'],
            'status': soap_response['Status']
        }), 200
    except Exception as e:
        return jsonify({'error': str(e)}), 500

@app.route('/api/v2/customers', methods=['POST'])
def create_customer():
    data = request.json

    try:
        # SOAP zahtev sa REST podacima
        response = soap_client.service.CreateCustomer(
            CustomerName=data['name'],
            EmailAddress=data['email'],
            Phone=data.get('phone', '')
        )

        return jsonify({
            'id': response['CustomerID'],
            'created': True
        }), 201
    except Exception as e:
        return jsonify({'error': str(e)}), 400

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, debug=False)
```

