## Opcija 2: Node.js + Express (BRŽA)

```javascript
const express = require('express');
const soap = require('soap');

const app = express();
app.use(express.json());

const WSDL_URL = 'http://legacy-soap-server:8080/services/CustomerService?wsdl';
let soapClient;

// Init SOAP client
soap.createClient(WSDL_URL, (err, client) => {
    if (err) throw err;
    soapClient = client;
    console.log('SOAP client connected');
});

// REST endpoint
app.get('/api/v2/customers/:id', async (req, res) => {
    try {
        // Pozovi SOAP (PREČICA!)
        const result = await new Promise((resolve, reject) => {
            soapClient.GetCustomer({ CustomerID: req.params.id }, (err, resp) => {
                if (err) reject(err);
                else resolve(resp);
            });
        });

        // Transform JSON
        res.json({
            id: result.CustomerID,
            name: result.CustomerName,
            email: result.EmailAddress
        });
    } catch (err) {
        res.status(500).json({ error: err.message });
    }
});

app.listen(5000, () => console.log('Adapter running on :5000'));
```

